<template>
  <LTPages
      :title="'日志管理'"
      :isNormal="false"
      :formConfig="formConfig"
      :tableConfig="tableConfig"
      @setSearchFields="getSearchFields"
      @tablePageForm="getTableForm"
  ></LTPages>
</template>
<script>
import * as logApi from "@/api/System/log.js";

export default {
  name: "Log",
  data() {
    return {
      //搜索配置
      formConfig: {
        labelWidth: "100px",
        itemNum: 5,
        formItemList: [
          {
            id: 1,
            type: "text",
            prop: "username",
            label: "用户名称",
            value: "",
          },
          {
            id: 2,
            type: "text",
            prop: "ip",
            label: "ip地址",
            value: "",
          },
          {
            id: 3,
            type: "datetimerange",
            prop: "alarmTime",
            label: "时间",
            value: "",
            format: "yyyy-MM-dd HH:mm:ss",
            style: "long",
          },
        ]
      },
      //表格配置
      tableConfig: {
        tableRefresh: true,
        tableLoading: false,
        tableHead: [
          {
            label: "用户名称",
            prop: "username",
          },
          {
            label: "操作",
            prop: "operation",
          },
          {
            label: "耗时",
            prop: "time",
          },
          {
            label: "IP地址",
            prop: "ip",
          },
          {
            label: "操作时间",
            prop: "createTime",
          },
        ],
        tableData: [],
        columnButton: [],
        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: true,
        total: 0,
        pageSize: 20,
        currentPage: 1,
      },
      //表格勾选
      checkTabelData: [],
      //查询参数
      params: {
        pageSize: 20,
        currentPage: 1,
      },
    };
  },
  created() {
    this.queryLog();
  },
  methods: {
    getSearchFields(data) {
      console.log(data);
      if (data.type != 'reset') {
        this.params.username = data.username;
        this.params.ip = data.ip;
        if (data.alarmTime && data.alarmTime.length != 0) {
          this.params.createTime = data.alarmTime[0] + "," + data.alarmTime[1];
        } else {
          delete this.params.createTime;
        }
        this.params.currentPage = 1;
        this.tableConfig.currentPage = 1;
      } else { //重置
        this.params = {
          pageSize: 20,
          currentPage: 1
        }
      }
      this.queryLog();
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.params.pageSize = page.pageSize;
      this.params.currentPage = page.pageNum;
      this.queryLog();
    },

    queryLog() {
      logApi.queryLogApi(this.params).then((res) => {
        if (res.data.code != "2000")
          return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000,
          });
        this.tableConfig.tableData = res.data.result.records;
        this.tableConfig.total = res.data.result.total;
      });
    },


  },
};
</script>