import request from '@/utils/request'
//日志查询
export function queryLogApi(query) {
    return request({
        url: '/apiIP/sys-log/query',
        method: 'post',
        data: query,
    })
}
//日志导出
export function exportLogApi(query) {
    return request({
        url: '/apiIP/sys-log/exportExcelByQueryDomain',
        method: 'post',
        data: query,
    })
}



  